// supplier.service.ts
import { Injectable, inject } from '@angular/core';
import { SupabaseService } from './Base/supabase.service';
import { BehaviorSubject } from 'rxjs';
import { Supplier } from '../models';
import { AuthService } from './Base/auth.service';


@Injectable({
  providedIn: 'root'
})
export class SupplierService {
  private supabaseService = inject(SupabaseService);
  private authService = inject(AuthService); // Inietta AuthService

  private suppliersSubject = new BehaviorSubject<Supplier[]>([]);
  public suppliers$ = this.suppliersSubject.asObservable();

  async loadSuppliers(): Promise<void> {
    try {
      // Ottieni il restaurant_id dell'utente corrente
      const user = this.authService.currentUserValue;
      if (!user) {
        console.error('No user authenticated');
        return;
      }

      const { data: restaurants, error: restaurantError } = await this.supabaseService.getSupabaseClient()
        .from('restaurants')
        .select('id')
        .eq('owner_id', user.id)
        .limit(1);

      if (restaurantError || !restaurants?.length) {
        console.error('❌ No restaurant found for user:', user.id);
        return;
      }

      const restaurantId = restaurants[0].id;

      const { data: suppliers, error } = await this.supabaseService.getSupabaseClient()
        .from('suppliers')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .order('company_name');

      if (error) throw error;
      this.suppliersSubject.next(suppliers || []);
    } catch (error) {
      console.error('Error loading suppliers:', error);
    }
  }

async createSupplier(supplier: Omit<Supplier, 'id' | 'restaurant_id' | 'created_at'>): Promise<Supplier | null> {
  try {
    // Ottieni il restaurant_id dell'utente corrente
    const user = this.authService.currentUserValue;
    if (!user) {
      console.error('No user authenticated');
      return null;
    }

    const { data: restaurants, error: restaurantError } = await this.supabaseService.getSupabaseClient()
      .from('restaurants')
      .select('id')
      .eq('owner_id', user.id)
      .limit(1);

    if (restaurantError || !restaurants?.length) {
      console.error('❌ No restaurant found for user:', user.id);
      return null;
    }

    const restaurantId = restaurants[0].id;

    const supplierWithRestaurant = {
      ...supplier,
      restaurant_id: restaurantId,
      // user_id può essere null per fornitori manuali
      user_id: supplier.user_id || null,
      // Assicurati che is_platform_supplier e is_approved siano sempre definiti
      is_platform_supplier: supplier.is_platform_supplier ?? false,
      is_approved: supplier.is_approved ?? true
    };

    const { data, error } = await this.supabaseService.getSupabaseClient()
      .from('suppliers')
      .insert(supplierWithRestaurant)
      .select()
      .single();

    if (error) throw error;
    await this.loadSuppliers();
    return data;
  } catch (error) {
    console.error('Error creating supplier:', error);
    return null;
  }
}

  getSuppliers(): Supplier[] {
    return this.suppliersSubject.value;
  }

  getSupplierById(id: string): Supplier | undefined {
    return this.suppliersSubject.value.find(s => s.id === id);
  }
}